const db = global.get('mysql');
let userId = msg.req.session.user?.id;
if (!userId) { msg.payload = { code: 400, message: "请先登录" }; return msg; }
let { contactId, items } = msg.req.body;
if (!contactId) { msg.payload = { code: 400, message: "请选择收货地址" }; return msg; }
if (!items || !items.length) { msg.payload = { code: 400, message: "订单商品不能为空" }; return msg; }

// 生成订单ID：年月日时分秒+3位随机数
let now = new Date();
let y = now.getFullYear(), m = String(now.getMonth()+1).padStart(2,'0'), d = String(now.getDate()).padStart(2,'0');
let hh = String(now.getHours()).padStart(2,'0'), mm = String(now.getMinutes()).padStart(2,'0'), ss = String(now.getSeconds()).padStart(2,'0');
let rand = String(Math.floor(Math.random()*900+100));
let orderId = y+m+d+hh+mm+ss+rand;

// 计算总价
let totalPrice = 0;
for (let item of items) {
    let detail = await db.sql("SELECT sale_price FROM product_detail WHERE id=?", item.detailId);
    if (detail.length > 0) totalPrice += parseFloat(detail[0].sale_price) * item.quantity;
}

// 插入订单
await db.sql("INSERT INTO `order`(id, price, paid, contact_id, user_id, create_time, update_time) VALUES(?,?,?,?,?,?,?)",
    orderId, totalPrice.toFixed(2), 0, contactId, userId, now, now);

// 插入订单明细 + 删除购物车中已勾选的商品
for (let item of items) {
    await db.sql("INSERT INTO order_detail(quantity, order_id, product_id, detail_id, create_time, update_time) VALUES(?,?,?,?,?,?)",
        item.quantity, orderId, item.productId, item.detailId, now, now);
    await db.sql("DELETE FROM cart WHERE user_id=? AND product_id=? AND detail_id=? AND checked=1",
        userId, item.productId, item.detailId);
}

msg.payload = { code: 200, message: "下单成功！", orderId: orderId };
return msg;

